  35→// errStop is a sentinel error used to break out of git log iteration.
  36→// Shared across strategies that iterate through git commits.
  37→// NOTE: A similar sentinel exists in checkpoint/temporary.go - this is intentional.
  38→// Each package needs its own package-scoped sentinel for git log iteration patterns.
  39→var errStop = errors.New("stop iteration")
  40→
  41→// IsAncestorOf checks if commit is an ancestor of (or equal to) target.
  42→// Returns true if target can reach commit by following parent links.
  43→// Limits search to 1000 commits to avoid excessive traversal.
  44→func IsAncestorOf(repo *git.Repository, commit, target plumbing.Hash) bool {
  45→	if commit == target {
  46→		return true
  47→	}
  48→
  49→	iter, err := repo.Log(&git.LogOptions{From: target})
  50→	if err != nil {
  51→		return false
  52→	}
  53→	defer iter.Close()
  54→
  55→	found := false
  56→	count := 0
  57→	_ = iter.ForEach(func(c *object.Commit) error { //nolint:errcheck // Best-effort search, errors are non-fatal
  58→		count++
  59→		if count > 1000 {
  60→			return errStop
  61→		}
  62→		if c.Hash == commit {
  63→			found = true
  64→			return errStop
  65→		}
  66→		return nil
  67→	})
  68→
  69→	return found
  70→}
