  72→// ListCheckpoints returns all checkpoints from the entire/checkpoints/v1 branch.
  73→// Scans sharded paths: <id[:2]>/<id[2:]>/ directories containing metadata.json.
  74→// Used by both manual-commit and auto-commit strategies.
  75→func ListCheckpoints() ([]CheckpointInfo, error) {
  76→	repo, err := OpenRepository()
  77→	if err != nil {
  78→		return nil, fmt.Errorf("failed to open git repository: %w", err)
  79→	}
  80→
  81→	refName := plumbing.NewBranchReferenceName(paths.MetadataBranchName)
  82→	ref, err := repo.Reference(refName, true)
  83→	if err != nil {
  84→		//nolint:nilerr // No sessions branch yet is expected, return empty list
  85→		return []CheckpointInfo{}, nil
  86→	}
  87→
  88→	commit, err := repo.CommitObject(ref.Hash())
  89→	if err != nil {
  90→		return nil, fmt.Errorf("failed to get commit object: %w", err)
  91→	}
  92→
  93→	tree, err := commit.Tree()
  94→	if err != nil {
  95→		return nil, fmt.Errorf("failed to get commit tree: %w", err)
  96→	}
  97→
  98→	var checkpoints []CheckpointInfo
  99→
 100→	// Scan sharded structure: <2-char-prefix>/<remaining-id>/metadata.json
 101→	// The tree has 2-character directories (hex buckets)
 102→	for _, bucketEntry := range tree.Entries {
 103→		if bucketEntry.Mode != filemode.Dir {
 104→			continue
 105→		}
 106→		// Bucket should be 2 hex chars
 107→		if len(bucketEntry.Name) != 2 {
 108→			continue
 109→		}
 110→
 111→		bucketTree, treeErr := repo.TreeObject(bucketEntry.Hash)
 112→		if treeErr != nil {
 113→			continue
 114→		}
 115→
 116→		// Each entry in the bucket is the remaining part of the checkpoint ID
 117→		for _, checkpointEntry := range bucketTree.Entries {
 118→			if checkpointEntry.Mode != filemode.Dir {
 119→				continue
 120→			}
 121→
 122→			checkpointTree, cpTreeErr := repo.TreeObject(checkpointEntry.Hash)
 123→			if cpTreeErr != nil {
 124→				continue
 125→			}
 126→
 127→			// Reconstruct checkpoint ID: <bucket><remaining>
 128→			checkpointIDStr := bucketEntry.Name + checkpointEntry.Name
 129→			checkpointID, cpErr := id.NewCheckpointID(checkpointIDStr)
 130→			if cpErr != nil {
 131→				// Skip invalid checkpoint IDs
 132→				continue
 133→			}
 134→
 135→			info := CheckpointInfo{
 136→				CheckpointID: checkpointID,
 137→			}
 138→
 139→			// Get details from metadata file (CheckpointSummary format)
 140→			if metadataFile, fileErr := checkpointTree.File(paths.MetadataFileName); fileErr == nil {
 141→				if content, contentErr := metadataFile.Contents(); contentErr == nil {
 142→					var summary checkpoint.CheckpointSummary
 143→					if json.Unmarshal([]byte(content), &summary) == nil && len(summary.Sessions) > 0 {
 144→						info.CheckpointsCount = summary.CheckpointsCount
 145→						info.FilesTouched = summary.FilesTouched
 146→						info.SessionCount = len(summary.Sessions)
 147→
 148→						// Read session-level metadata for Agent, SessionID, CreatedAt, SessionIDs
 149→						for i, sessionPaths := range summary.Sessions {
 150→							if sessionPaths.Metadata != "" {
 151→								// SessionFilePaths now contains absolute paths with leading "/"
 152→								// Strip the leading "/" for tree.File() which expects paths without leading slash
 153→								sessionMetadataPath := strings.TrimPrefix(sessionPaths.Metadata, "/")
 154→								if sessionFile, sErr := tree.File(sessionMetadataPath); sErr == nil {
 155→									if sessionContent, scErr := sessionFile.Contents(); scErr == nil {
 156→										var sessionMetadata checkpoint.CommittedMetadata
 157→										if json.Unmarshal([]byte(sessionContent), &sessionMetadata) == nil {
 158→											info.SessionIDs = append(info.SessionIDs, sessionMetadata.SessionID)
 159→											// Use first session's metadata for Agent, SessionID, CreatedAt
 160→											if i == 0 {
 161→												info.Agent = sessionMetadata.Agent
 162→												info.SessionID = sessionMetadata.SessionID
 163→												info.CreatedAt = sessionMetadata.CreatedAt
 164→												info.IsTask = sessionMetadata.IsTask
 165→												info.ToolUseID = sessionMetadata.ToolUseID
 166→											}
 167→										}
 168→									}
 169→								}
 170→							}
 171→						}
 172→					}
 173→				}
 174→			}
 175→
 176→			checkpoints = append(checkpoints, info)
 177→		}
 178→	}
 179→
 180→	// Sort by time (most recent first)
 181→	sort.Slice(checkpoints, func(i, j int) bool {
 182→		return checkpoints[i].CreatedAt.After(checkpoints[j].CreatedAt)
 183→	})
 184→
 185→	return checkpoints, nil
 186→}
