 198→// isProtectedPath returns true if relPath is inside a directory that should
 199→// never be modified or deleted during rewind or other destructive operations.
 200→// Protected directories include git internals, entire metadata, and all
 201→// registered agent config directories.
 202→func isProtectedPath(relPath string) bool {
 203→	for _, dir := range protectedDirs() {
 204→		if relPath == dir || strings.HasPrefix(relPath, dir+string(filepath.Separator)) {
 205→			return true
 206→		}
 207→	}
 208→	return false
 209→}
