 233→// homeRelativePath strips the $HOME/ prefix from an absolute path,
 234→// returning a home-relative path suitable for persisting in metadata.
 235→// Returns "" if the path is empty or not under $HOME.
 236→func homeRelativePath(absPath string) string {
 237→	if absPath == "" {
 238→		return ""
 239→	}
 240→	home, err := os.UserHomeDir()
 241→	if err != nil || home == "" {
 242→		return ""
 243→	}
 244→	prefix := home + string(filepath.Separator)
 245→	if !strings.HasPrefix(absPath, prefix) {
 246→		return ""
 247→	}
 248→	return absPath[len(prefix):]
 249→}
