 251→// isSpecificAgentType returns true if the agent type is a known, specific value
 252→// (not empty and not the generic "Agent" fallback).
 253→func isSpecificAgentType(t agent.AgentType) bool {
 254→	return t != "" && t != DefaultAgentType
 255→}
