 257→// resolveAgentType picks the best agent type from the context and existing state.
 258→// Priority: existing state (if specific) > context value > default fallback.
 259→func resolveAgentType(ctxAgentType agent.AgentType, state *SessionState) agent.AgentType {
 260→	if state != nil && isSpecificAgentType(state.AgentType) {
 261→		return state.AgentType
 262→	}
 263→	if ctxAgentType != "" {
 264→		return ctxAgentType
 265→	}
 266→	return DefaultAgentType
 267→}
