 269→// ensureMetadataBranch creates the orphan entire/checkpoints/v1 branch if it doesn't exist.
 270→// This branch has no parent and starts with an empty tree.
 271→func EnsureMetadataBranch(repo *git.Repository) error {
 272→	refName := plumbing.NewBranchReferenceName(paths.MetadataBranchName)
 273→
 274→	// Check if branch already exists
 275→	_, err := repo.Reference(refName, true)
 276→	if err == nil {
 277→		// Branch already exists
 278→		return nil
 279→	}
 280→
 281→	// Create empty tree (no files)
 282→	emptyTree := &object.Tree{Entries: []object.TreeEntry{}}
 283→	obj := repo.Storer.NewEncodedObject()
 284→	if err := emptyTree.Encode(obj); err != nil {
 285→		return fmt.Errorf("failed to encode empty tree: %w", err)
 286→	}
 287→	emptyTreeHash, err := repo.Storer.SetEncodedObject(obj)
 288→	if err != nil {
 289→		return fmt.Errorf("failed to store empty tree: %w", err)
 290→	}
 291→
 292→	// Create orphan commit (no parent)
 293→	now := time.Now()
 294→	sig := object.Signature{
 295→		Name:  "Entire",
 296→		Email: "entire@local",
 297→		When:  now,
 298→	}
 299→
 300→	commit := &object.Commit{
 301→		TreeHash:  emptyTreeHash,
 302→		Author:    sig,
 303→		Committer: sig,
 304→		Message:   "Initialize metadata branch\n\nThis branch stores session metadata for the auto-commit strategy.\n",
 305→	}
 306→	// Note: No ParentHashes - this is an orphan commit
 307→
 308→	commitObj := repo.Storer.NewEncodedObject()
 309→	if err := commit.Encode(commitObj); err != nil {
 310→		return fmt.Errorf("failed to encode orphan commit: %w", err)
 311→	}
 312→	commitHash, err := repo.Storer.SetEncodedObject(commitObj)
 313→	if err != nil {
 314→		return fmt.Errorf("failed to store orphan commit: %w", err)
 315→	}
 316→
 317→	// Create branch reference
 318→	ref := plumbing.NewHashReference(refName, commitHash)
 319→	if err := repo.Storer.SetReference(ref); err != nil {
 320→		return fmt.Errorf("failed to create metadata branch: %w", err)
 321→	}
 322→
 323→	fmt.Fprintf(os.Stderr, "✓ Created orphan branch '%s' for session metadata\n", paths.MetadataBranchName)
 324→	return nil
 325→}
