 327→// readCheckpointMetadata reads metadata.json from a checkpoint path on entire/checkpoints/v1.
 328→// With the new format, root metadata.json is a CheckpointSummary with Agents array.
 329→// This function reads the summary and extracts relevant fields into CheckpointInfo,
 330→// also reading session-level metadata for IsTask/ToolUseID fields.
 331→func ReadCheckpointMetadata(tree *object.Tree, checkpointPath string) (*CheckpointInfo, error) {
 332→	metadataPath := checkpointPath + "/metadata.json"
 333→	file, err := tree.File(metadataPath)
 334→	if err != nil {
 335→		return nil, fmt.Errorf("failed to find metadata at %s: %w", metadataPath, err)
 336→	}
 337→
 338→	content, err := file.Contents()
 339→	if err != nil {
 340→		return nil, fmt.Errorf("failed to read metadata: %w", err)
 341→	}
 342→
 343→	// Try to parse as CheckpointSummary first (new format)
 344→	var summary checkpoint.CheckpointSummary
 345→	if err := json.Unmarshal([]byte(content), &summary); err == nil {
 346→		// If we have sessions array, this is the new format
 347→		if len(summary.Sessions) > 0 {
 348→			info := &CheckpointInfo{
 349→				CheckpointID:     summary.CheckpointID,
 350→				CheckpointsCount: summary.CheckpointsCount,
 351→				FilesTouched:     summary.FilesTouched,
 352→				SessionCount:     len(summary.Sessions),
 353→			}
 354→
 355→			// Read all sessions' metadata to populate SessionIDs and get other fields from first session
 356→			var sessionIDs []string
 357→			for i, sessionPaths := range summary.Sessions {
 358→				if sessionPaths.Metadata != "" {
 359→					// SessionFilePaths now contains absolute paths with leading "/"
 360→					// Strip the leading "/" for tree.File() which expects paths without leading slash
 361→					sessionMetadataPath := strings.TrimPrefix(sessionPaths.Metadata, "/")
 362→					if sessionFile, err := tree.File(sessionMetadataPath); err == nil {
 363→						if sessionContent, err := sessionFile.Contents(); err == nil {
 364→							var sessionMetadata checkpoint.CommittedMetadata
 365→							if json.Unmarshal([]byte(sessionContent), &sessionMetadata) == nil {
 366→								sessionIDs = append(sessionIDs, sessionMetadata.SessionID)
 367→								// Use first session for Agent, SessionID, CreatedAt, IsTask, ToolUseID
 368→								if i == 0 {
 369→									info.Agent = sessionMetadata.Agent
 370→									info.SessionID = sessionMetadata.SessionID
 371→									info.CreatedAt = sessionMetadata.CreatedAt
 372→									info.IsTask = sessionMetadata.IsTask
 373→									info.ToolUseID = sessionMetadata.ToolUseID
 374→								}
 375→							}
 376→						}
 377→					}
 378→				}
 379→			}
 380→			info.SessionIDs = sessionIDs
 381→
 382→			return info, nil
 383→		}
 384→	}
 385→
 386→	// Fall back to parsing as CheckpointInfo (old format or direct info)
 387→	var metadata CheckpointInfo
 388→	if err := json.Unmarshal([]byte(content), &metadata); err != nil {
 389→		return nil, fmt.Errorf("failed to parse metadata: %w", err)
 390→	}
 391→
 392→	return &metadata, nil
 393→}
