 415→// ExtractFirstPrompt extracts and truncates the first meaningful prompt from prompt content.
 416→// Prompts are separated by "\n\n---\n\n". Skips empty prompts and separator-only content.
 417→// Returns empty string if no valid prompt is found.
 418→func ExtractFirstPrompt(content string) string {
 419→	if content == "" {
 420→		return ""
 421→	}
 422→
 423→	// Prompts are separated by "\n\n---\n\n"
 424→	// Find the first non-empty prompt
 425→	prompts := strings.Split(content, "\n\n---\n\n")
 426→	var firstPrompt string
 427→	for _, p := range prompts {
 428→		cleaned := strings.TrimSpace(p)
 429→		// Skip empty prompts or prompts that are just dashes/separators
 430→		if cleaned == "" || isOnlySeparators(cleaned) {
 431→			continue
 432→		}
 433→		firstPrompt = cleaned
 434→		break
 435→	}
 436→
 437→	if firstPrompt == "" {
 438→		return ""
 439→	}
 440→
 441→	return TruncateDescription(firstPrompt, MaxDescriptionLength)
 442→}
