 444→// ReadSessionPromptFromTree reads the first meaningful prompt from a checkpoint's prompt.txt file in a git tree.
 445→// Returns an empty string if the prompt cannot be read.
 446→func ReadSessionPromptFromTree(tree *object.Tree, checkpointPath string) string {
 447→	promptPath := checkpointPath + "/" + paths.PromptFileName
 448→	file, err := tree.File(promptPath)
 449→	if err != nil {
 450→		return ""
 451→	}
 452→
 453→	content, err := file.Contents()
 454→	if err != nil {
 455→		return ""
 456→	}
 457→
 458→	return ExtractFirstPrompt(content)
 459→}
