 461→// isOnlySeparators checks if a string contains only dashes, spaces, and newlines.
 462→func isOnlySeparators(s string) bool {
 463→	for _, r := range s {
 464→		if r != '-' && r != ' ' && r != '\n' && r != '\r' && r != '\t' {
 465→			return false
 466→		}
 467→	}
 468→	return true
 469→}
