 471→// ReadAllSessionPromptsFromTree reads the first prompt for all sessions in a multi-session checkpoint.
 472→// Returns a slice of prompts parallel to sessionIDs (oldest to newest).
 473→// For single-session checkpoints, returns a slice with just the root prompt.
 474→func ReadAllSessionPromptsFromTree(tree *object.Tree, checkpointPath string, sessionCount int, sessionIDs []string) []string {
 475→	if sessionCount <= 1 || len(sessionIDs) <= 1 {
 476→		// Single session - just return the root prompt
 477→		prompt := ReadSessionPromptFromTree(tree, checkpointPath)
 478→		if prompt != "" {
 479→			return []string{prompt}
 480→		}
 481→		return nil
 482→	}
 483→
 484→	// Multi-session: read prompts from archived folders (0/, 1/, etc.) and root
 485→	prompts := make([]string, len(sessionIDs))
 486→
 487→	// Read archived session prompts (folders 0, 1, ... N-2)
 488→	for i := range sessionCount - 1 {
 489→		archivedPath := fmt.Sprintf("%s/%d", checkpointPath, i)
 490→		prompts[i] = ReadSessionPromptFromTree(tree, archivedPath)
 491→	}
 492→
 493→	// Read the most recent session prompt (at root level)
 494→	prompts[len(prompts)-1] = ReadSessionPromptFromTree(tree, checkpointPath)
 495→
 496→	return prompts
 497→}
