 544→// OpenRepository opens the git repository with linked worktree support enabled.
 545→// It uses git.PlainOpenWithOptions with EnableDotGitCommonDir set to true,
 546→// which is required for proper operation in git worktrees created via 'git worktree add'.
 547→//
 548→// Without EnableDotGitCommonDir, go-git operations in worktrees can silently fail:
 549→// - Commits appear to succeed but are not persisted
 550→// - Refs are written to incorrect locations
 551→// - The worktree's HEAD/index don't get updated properly
 552→//
 553→// This happens because worktrees use .git as a file (pointing to the main repo)
 554→// rather than a directory, and go-git needs to route paths correctly between
 555→// shared (.git/) and per-worktree (.git/worktrees/<name>/) locations.
 556→//
 557→// The function first uses 'git rev-parse --show-toplevel' to find the repository
 558→// root, which works correctly even when called from a subdirectory within the repo.
 559→func OpenRepository() (*git.Repository, error) {
 560→	// First, find the repository root using git rev-parse --show-toplevel
 561→	// This works correctly from any subdirectory within the repository
 562→	repoRoot, err := GetWorktreePath()
 563→	if err != nil {
 564→		// Fallback to current directory if git command fails
 565→		// (e.g., if git is not installed or we're not in a repo)
 566→		repoRoot = "."
 567→	}
 568→
 569→	repo, err := git.PlainOpenWithOptions(repoRoot, &git.PlainOpenOptions{
 570→		EnableDotGitCommonDir: true,
 571→	})
 572→	if err != nil {
 573→		return nil, fmt.Errorf("failed to open repository: %w", err)
 574→	}
 575→	return repo, nil
 576→}
 577→
 578→// IsInsideWorktree returns true if the current directory is inside a git worktree
 579→// (as opposed to the main repository). Worktrees have .git as a file pointing
 580→// to the main repo, while the main repo has .git as a directory.
 581→// This function works correctly from any subdirectory within the repository.
 582→func IsInsideWorktree() bool {
 583→	// First find the repository root
 584→	repoRoot, err := GetWorktreePath()
 585→	if err != nil {
 586→		return false
 587→	}
 588→
 589→	gitPath := filepath.Join(repoRoot, gitDir)
 590→	gitInfo, err := os.Stat(gitPath)
 591→	if err != nil {
 592→		return false
 593→	}
 594→	return !gitInfo.IsDir()
 595→}
 596→
 597→// GetMainRepoRoot returns the root directory of the main repository.
 598→// In the main repo, this is the worktree path (repo root).
 599→// In a worktree, this parses the .git file to find the main repo.
 600→// This function works correctly from any subdirectory within the repository.
 601→//
 602→// Per gitrepository-layout(5), a worktree's .git file is a "gitfile" containing
 603→// "gitdir: <path>" pointing to $GIT_DIR/worktrees/<id> in the main repository.
 604→// See: https://git-scm.com/docs/gitrepository-layout
 605→func GetMainRepoRoot() (string, error) {
 606→	// First find the worktree/repo root
 607→	repoRoot, err := GetWorktreePath()
 608→	if err != nil {
 609→		return "", fmt.Errorf("failed to get worktree path: %w", err)
 610→	}
 611→
 612→	if !IsInsideWorktree() {
 613→		return repoRoot, nil
 614→	}
 615→
 616→	// Worktree .git file contains: "gitdir: /path/to/main/.git/worktrees/<id>"
 617→	gitFilePath := filepath.Join(repoRoot, gitDir)
 618→	content, err := os.ReadFile(gitFilePath) //nolint:gosec // G304: gitFilePath is constructed from repo root, not user input
 619→	if err != nil {
 620→		return "", fmt.Errorf("failed to read .git file: %w", err)
 621→	}
 622→
 623→	gitdir := strings.TrimSpace(string(content))
 624→	gitdir = strings.TrimPrefix(gitdir, "gitdir: ")
 625→
 626→	// Extract main repo root: everything before "/.git/"
 627→	idx := strings.LastIndex(gitdir, "/.git/")
 628→	if idx < 0 {
 629→		return "", fmt.Errorf("unexpected gitdir format: %s", gitdir)
 630→	}
 631→	return gitdir[:idx], nil
 632→}
 633→
 634→// GetGitCommonDir returns the path to the shared git directory.
 635→// In a regular checkout, this is .git/
 636→// In a worktree, this is the main repo's .git/ (not .git/worktrees/<name>/)
 637→// Uses git rev-parse --git-common-dir for reliable handling of worktrees.
 638→func GetGitCommonDir() (string, error) {
 639→	ctx := context.Background()
 640→	cmd := exec.CommandContext(ctx, "git", "rev-parse", "--git-common-dir")
 641→	cmd.Dir = "."
 642→	output, err := cmd.Output()
 643→	if err != nil {
 644→		return "", fmt.Errorf("failed to get git common dir: %w", err)
 645→	}
 646→
 647→	commonDir := strings.TrimSpace(string(output))
 648→
 649→	// git rev-parse --git-common-dir returns relative paths from the working directory,
 650→	// so we need to make it absolute if it isn't already
 651→	if !filepath.IsAbs(commonDir) {
 652→		commonDir = filepath.Join(".", commonDir)
 653→	}
 654→
 655→	return filepath.Clean(commonDir), nil
 656→}
 657→
 658→// GetWorktreePath returns the absolute path to the current worktree root.
 659→// This is the working directory path, not the git directory.
 660→func GetWorktreePath() (string, error) {
 661→	ctx := context.Background()
 662→	cmd := exec.CommandContext(ctx, "git", "rev-parse", "--show-toplevel")
 663→	output, err := cmd.Output()
 664→	if err != nil {
 665→		return "", fmt.Errorf("failed to get worktree path: %w", err)
 666→	}
 667→	return strings.TrimSpace(string(output)), nil
 668→}
