 670→// EnsureEntireGitignore ensures all required entries are in .entire/.gitignore
 671→// Works correctly from any subdirectory within the repository.
 672→func EnsureEntireGitignore() error {
 673→	// Get absolute path for the gitignore file
 674→	gitignoreAbs, err := paths.AbsPath(entireGitignore)
 675→	if err != nil {
 676→		gitignoreAbs = entireGitignore // Fallback to relative
 677→	}
 678→
 679→	// Read existing content
 680→	var content string
 681→	if data, err := os.ReadFile(gitignoreAbs); err == nil { //nolint:gosec // path is from AbsPath or constant
 682→		content = string(data)
 683→	}
 684→
 685→	// All entries that should be in .entire/.gitignore
 686→	requiredEntries := []string{
 687→		"tmp/",
 688→		"settings.local.json",
 689→		"metadata/",
 690→		"logs/",
 691→	}
 692→
 693→	// Track what needs to be added
 694→	var toAdd []string
 695→	for _, entry := range requiredEntries {
 696→		if !strings.Contains(content, entry) {
 697→			toAdd = append(toAdd, entry)
 698→		}
 699→	}
 700→
 701→	// Nothing to add
 702→	if len(toAdd) == 0 {
 703→		return nil
 704→	}
 705→
 706→	// Ensure .entire directory exists
 707→	if err := os.MkdirAll(filepath.Dir(gitignoreAbs), 0o750); err != nil {
 708→		return fmt.Errorf("failed to create .entire directory: %w", err)
 709→	}
 710→
 711→	// Append missing entries to gitignore
 712→	var sb strings.Builder
 713→	for _, entry := range toAdd {
 714→		sb.WriteString(entry + "\n")
 715→	}
 716→	content += sb.String()
 717→
 718→	if err := os.WriteFile(gitignoreAbs, []byte(content), 0o644); err != nil { //nolint:gosec // path is from AbsPath or constant
 719→		return fmt.Errorf("failed to write gitignore: %w", err)
 720→	}
 721→	return nil
 722→}
 723→
 724→// checkCanRewind checks if working directory is clean enough for rewind.
 725→// Returns (canRewind, reason, error). Shared by shadow and linear-shadow strategies.
 726→func checkCanRewind() (bool, string, error) {
 727→	repo, err := OpenRepository()
 728→	if err != nil {
 729→		return false, "", fmt.Errorf("failed to open git repository: %w", err)
 730→	}
 731→
 732→	worktree, err := repo.Worktree()
 733→	if err != nil {
 734→		return false, "", fmt.Errorf("failed to get worktree: %w", err)
 735→	}
 736→
 737→	status, err := worktree.Status()
 738→	if err != nil {
 739→		return false, "", fmt.Errorf("failed to get status: %w", err)
 740→	}
 741→
 742→	if status.IsClean() {
 743→		return true, "", nil
 744→	}
 745→
 746→	var modified, added, deleted []string
 747→	for file, st := range status {
 748→		// Skip .entire directory
 749→		if paths.IsInfrastructurePath(file) {
 750→			continue
 751→		}
 752→
 753→		// Skip untracked files
 754→		if st.Worktree == git.Untracked {
 755→			continue
 756→		}
 757→
 758→		switch {
 759→		case st.Staging == git.Added || st.Worktree == git.Added:
 760→			added = append(added, file)
 761→		case st.Staging == git.Deleted || st.Worktree == git.Deleted:
 762→			deleted = append(deleted, file)
 763→		case st.Staging == git.Modified || st.Worktree == git.Modified:
 764→			modified = append(modified, file)
 765→		}
 766→	}
 767→
 768→	if len(modified) == 0 && len(added) == 0 && len(deleted) == 0 {
 769→		return true, "", nil
 770→	}
 771→
 772→	var msg strings.Builder
 773→	msg.WriteString("You have uncommitted changes:\n")
 774→	for _, f := range modified {
 775→		msg.WriteString(fmt.Sprintf("  modified:   %s\n", f))
 776→	}
 777→	for _, f := range added {
 778→		msg.WriteString(fmt.Sprintf("  added:      %s\n", f))
 779→	}
 780→	for _, f := range deleted {
 781→		msg.WriteString(fmt.Sprintf("  deleted:    %s\n", f))
 782→	}
 783→	msg.WriteString("\nPlease commit or stash your changes before rewinding.")
 784→
 785→	return false, msg.String(), nil
 786→}
 787→
 788→// checkCanRewindWithWarning checks working directory and returns a warning with diff stats.
 789→// Unlike checkCanRewind, this always returns canRewind=true but includes a warning message
 790→// with +/- line stats for uncommitted changes. Used by manual-commit strategy.
 791→func checkCanRewindWithWarning() (bool, string, error) {
 792→	repo, err := OpenRepository()
 793→	if err != nil {
 794→		// Can't open repo - still allow rewind but without stats
 795→		return true, "", nil //nolint:nilerr // Rewind allowed even if repo can't be opened
 796→	}
 797→
 798→	worktree, err := repo.Worktree()
 799→	if err != nil {
 800→		return true, "", nil //nolint:nilerr // Rewind allowed even if worktree can't be accessed
 801→	}
 802→
 803→	status, err := worktree.Status()
 804→	if err != nil {
 805→		return true, "", nil //nolint:nilerr // Rewind allowed even if status can't be retrieved
 806→	}
 807→
 808→	if status.IsClean() {
 809→		return true, "", nil
 810→	}
 811→
 812→	// Get HEAD commit tree for comparison - if we can't get it, just return without stats
 813→	head, err := repo.Head()
 814→	if err != nil {
 815→		return true, "", nil //nolint:nilerr // Rewind allowed even without HEAD (e.g., empty repo)
 816→	}
 817→
 818→	headCommit, err := repo.CommitObject(head.Hash())
 819→	if err != nil {
 820→		return true, "", nil //nolint:nilerr // Rewind allowed even if commit lookup fails
 821→	}
 822→
 823→	headTree, err := headCommit.Tree()
 824→	if err != nil {
 825→		return true, "", nil //nolint:nilerr // Rewind allowed even if tree lookup fails
 826→	}
 827→
 828→	type fileChange struct {
 829→		status   string // "modified", "added", "deleted"
 830→		added    int
 831→		removed  int
 832→		filename string
 833→	}
 834→
 835→	var changes []fileChange
 836→	// Use repo root, not cwd - git status returns paths relative to repo root
 837→	repoRoot, err := GetWorktreePath()
 838→	if err != nil {
 839→		return true, "", nil //nolint:nilerr // Rewind allowed even if repo root lookup fails
 840→	}
 841→
 842→	for file, st := range status {
 843→		// Skip .entire directory
 844→		if paths.IsInfrastructurePath(file) {
 845→			continue
 846→		}
 847→
 848→		// Skip untracked files
 849→		if st.Worktree == git.Untracked {
 850→			continue
 851→		}
 852→
 853→		var change fileChange
 854→		change.filename = file
 855→
 856→		switch {
 857→		case st.Staging == git.Added || st.Worktree == git.Added:
 858→			change.status = "added"
 859→			// New file - count all lines as added
 860→			absPath := filepath.Join(repoRoot, file)
 861→			if content, err := os.ReadFile(absPath); err == nil { //nolint:gosec // absPath is repo root + relative path from git status
 862→				change.added = countLines(content)
 863→			}
 864→		case st.Staging == git.Deleted || st.Worktree == git.Deleted:
 865→			change.status = "deleted"
 866→			// Deleted file - count lines from HEAD as removed
 867→			if entry, err := headTree.File(file); err == nil {
 868→				if content, err := entry.Contents(); err == nil {
 869→					change.removed = countLines([]byte(content))
 870→				}
 871→			}
 872→		case st.Staging == git.Modified || st.Worktree == git.Modified:
 873→			change.status = "modified"
 874→			// Modified file - compute diff stats
 875→			var headContent, workContent []byte
 876→			if entry, err := headTree.File(file); err == nil {
 877→				if content, err := entry.Contents(); err == nil {
 878→					headContent = []byte(content)
 879→				}
 880→			}
 881→			absPath := filepath.Join(repoRoot, file)
 882→			if content, err := os.ReadFile(absPath); err == nil { //nolint:gosec // absPath is repo root + relative path from git status
 883→				workContent = content
 884→			}
 885→			if headContent != nil && workContent != nil {
 886→				change.added, change.removed = computeDiffStats(headContent, workContent)
 887→			}
 888→		default:
 889→			continue
 890→		}
 891→
 892→		changes = append(changes, change)
 893→	}
 894→
 895→	if len(changes) == 0 {
 896→		return true, "", nil
 897→	}
 898→
 899→	// Sort changes by filename for consistent output
 900→	sort.Slice(changes, func(i, j int) bool {
 901→		return changes[i].filename < changes[j].filename
 902→	})
 903→
 904→	var msg strings.Builder
 905→	msg.WriteString("The following uncommitted changes will be reverted:\n")
 906→
 907→	totalAdded, totalRemoved := 0, 0
 908→	for _, c := range changes {
 909→		totalAdded += c.added
 910→		totalRemoved += c.removed
 911→
 912→		var stats string
 913→		switch {
 914→		case c.added > 0 && c.removed > 0:
 915→			stats = fmt.Sprintf("+%d/-%d", c.added, c.removed)
 916→		case c.added > 0:
 917→			stats = fmt.Sprintf("+%d", c.added)
 918→		case c.removed > 0:
 919→			stats = fmt.Sprintf("-%d", c.removed)
 920→		}
 921→
 922→		msg.WriteString(fmt.Sprintf("  %-10s %s", c.status+":", c.filename))
 923→		if stats != "" {
 924→			msg.WriteString(fmt.Sprintf(" (%s)", stats))
 925→		}
 926→		msg.WriteString("\n")
 927→	}
 928→
 929→	if totalAdded > 0 || totalRemoved > 0 {
 930→		msg.WriteString(fmt.Sprintf("\nTotal: +%d/-%d lines\n", totalAdded, totalRemoved))
 931→	}
 932→
 933→	return true, msg.String(), nil
 934→}
