 936→// countLines counts the number of lines in content.
 937→func countLines(content []byte) int {
 938→	if len(content) == 0 {
 939→		return 0
 940→	}
 941→	count := 1
 942→	for _, b := range content {
 943→		if b == '\n' {
 944→			count++
 945→		}
 946→	}
 947→	// Don't count trailing newline as extra line
 948→	if len(content) > 0 && content[len(content)-1] == '\n' {
 949→		count--
 950→	}
 951→	return count
 952→}
 953→
 954→// computeDiffStats computes added and removed line counts between old and new content.
 955→// Uses a simple line-based diff algorithm.
 956→func computeDiffStats(oldContent, newContent []byte) (added, removed int) {
 957→	oldLines := splitLines(oldContent)
 958→	newLines := splitLines(newContent)
 959→
 960→	// Build a set of old lines with counts
 961→	oldSet := make(map[string]int)
 962→	for _, line := range oldLines {
 963→		oldSet[line]++
 964→	}
 965→
 966→	// Check which new lines are truly new
 967→	for _, line := range newLines {
 968→		if oldSet[line] > 0 {
 969→			oldSet[line]--
 970→		} else {
 971→			added++
 972→		}
 973→	}
 974→
 975→	// Remaining old lines are removed
 976→	for _, count := range oldSet {
 977→		removed += count
 978→	}
 979→
 980→	return added, removed
 981→}
 982→
 983→// splitLines splits content into lines, preserving empty lines.
 984→func splitLines(content []byte) []string {
 985→	if len(content) == 0 {
 986→		return nil
 987→	}
 988→	s := string(content)
 989→	// Remove trailing newline to avoid empty last element
 990→	s = strings.TrimSuffix(s, "\n")
 991→	return strings.Split(s, "\n")
 992→}
