1000→// StageFilesContext describes what type of staging operation this is (for messages).
1001→type StageFilesContext string
1002→
1003→const (
1004→	// StageForSession is used when staging files for a session checkpoint.
1005→	StageForSession StageFilesContext = "session"
1006→	// StageForTask is used when staging files for a task checkpoint.
1007→	StageForTask StageFilesContext = "task"
1008→)
