1010→// StageFiles stages modified, new, and deleted files to the git worktree.
1011→//
1012→// This function handles three categories of file changes:
1013→//  1. Modified files: existing files that have been changed
1014→//  2. New files: files that were created during the session
1015→//  3. Deleted files: files that were removed during the session
1016→//
1017→// Error Handling Strategy:
1018→//   - Individual file staging errors are logged to stderr but don't fail the operation
1019→//   - This ensures that partial staging succeeds even if some files have issues
1020→//   - If a modified file no longer exists, it's treated as a deletion
1021→//
1022→// The stageCtx parameter is used for user-facing messages to indicate whether
1023→// this is staging for a session checkpoint or a task checkpoint.
1024→func StageFiles(worktree *git.Worktree, modified, newFiles, deleted []string, stageCtx StageFilesContext) {
1025→	// Get repo root for resolving file paths
1026→	// This is critical because fileExists() uses os.Stat() which resolves relative to CWD,
1027→	// but worktree.Add/Remove resolve relative to repo root. If CWD != repo root,
1028→	// fileExists() could return false for existing files, causing worktree.Remove()
1029→	// to incorrectly delete them.
1030→	repoRoot := worktree.Filesystem.Root()
1031→
1032→	// Stage modified files
1033→	for _, file := range modified {
1034→		// Resolve path relative to repo root for existence check
1035→		absPath := filepath.Join(repoRoot, file)
1036→		if fileExists(absPath) {
1037→			if _, err := worktree.Add(file); err != nil {
1038→				fmt.Fprintf(os.Stderr, "  Failed to stage %s: %v\n", file, err)
1039→			} else {
1040→				fmt.Fprintf(os.Stderr, "  Staged: %s\n", file)
1041→			}
1042→		} else {
1043→			// File was deleted - stage the deletion
1044→			if _, err := worktree.Remove(file); err != nil {
1045→				fmt.Fprintf(os.Stderr, "  File not found or deleted: %s\n", file)
1046→			}
1047→		}
1048→	}
1049→
1050→	// Stage new files
1051→	if len(newFiles) > 0 {
1052→		fmt.Fprintf(os.Stderr, "Staging %d new files created during %s:\n", len(newFiles), stageCtx)
1053→		for _, file := range newFiles {
1054→			if _, err := worktree.Add(file); err != nil {
1055→				fmt.Fprintf(os.Stderr, "  Failed to stage %s: %v\n", file, err)
1056→			} else {
1057→				fmt.Fprintf(os.Stderr, "  Staged new file: %s\n", file)
1058→			}
1059→		}
1060→	}
1061→
1062→	// Stage deleted files
1063→	for _, file := range deleted {
1064→		if _, err := worktree.Remove(file); err != nil {
1065→			fmt.Fprintf(os.Stderr, "  Failed to stage deleted file %s: %v\n", file, err)
1066→		} else {
1067→			fmt.Fprintf(os.Stderr, "  Staged deleted file: %s\n", file)
1068→		}
1069→	}
1070→}
