1079→	repo, err := OpenRepository()
1080→	if err != nil {
1081→		return nil, fmt.Errorf("failed to open repository: %w", err)
1082→	}
1083→
1084→	commitHash := plumbing.NewHash(point.ID)
1085→	commit, err := repo.CommitObject(commitHash)
1086→	if err != nil {
1087→		return nil, fmt.Errorf("failed to get commit: %w", err)
1088→	}
1089→
1090→	tree, err := commit.Tree()
1091→	if err != nil {
1092→		return nil, fmt.Errorf("failed to get tree: %w", err)
1093→	}
1094→
1095→	// Read checkpoint.json from the tree
1096→	checkpointPath := point.MetadataDir + "/checkpoint.json"
