1161→// ErrBranchNotFound is returned by DeleteBranchCLI when the branch does not exist.
1162→var ErrBranchNotFound = errors.New("branch not found")
1163→
1164→// DeleteBranchCLI deletes a git branch using the git CLI.
1165→// Uses `git branch -D` instead of go-git's RemoveReference because go-git v5
1166→// doesn't properly persist deletions when refs are packed (.git/packed-refs)
1167→// or in a worktree context. This is the same class of go-git v5 bug that
1168→// affects checkout and reset --hard (see HardResetWithProtection).
1169→//
1170→// Returns ErrBranchNotFound if the branch does not exist, allowing callers
1171→// to use errors.Is for idempotent deletion patterns.
1172→func DeleteBranchCLI(branchName string) error {
1173→	ctx := context.Background()
1174→
1175→	// Pre-check: verify the branch exists so callers get a structured error
1176→	// instead of parsing git's output string (which varies across locales).
1177→	// git show-ref exits 1 for "not found" and 128+ for fatal errors (corrupt
1178→	// repo, permissions, not a git directory). Only map exit code 1 to
1179→	// ErrBranchNotFound; propagate other failures as-is.
1180→	check := exec.CommandContext(ctx, "git", "show-ref", "--verify", "--quiet", "refs/heads/"+branchName) //nolint:gosec // branchName comes from internal shadow branch naming
1181→	if err := check.Run(); err != nil {
1182→		var exitErr *exec.ExitError
1183→		if errors.As(err, &exitErr) && exitErr.ExitCode() == 1 {
1184→			return fmt.Errorf("%w: %s", ErrBranchNotFound, branchName)
1185→		}
1186→		return fmt.Errorf("failed to check branch %s: %w", branchName, err)
1187→	}
1188→
1189→	cmd := exec.CommandContext(ctx, "git", "branch", "-D", "--", branchName)
1190→	if output, err := cmd.CombinedOutput(); err != nil {
1191→		return fmt.Errorf("failed to delete branch %s: %s: %w", branchName, strings.TrimSpace(string(output)), err)
1192→	}
1193→	return nil
1194→}
