1196→// branchExistsCLI checks if a branch exists using git CLI.
1197→// Returns nil if the branch exists, or an error if it does not.
1198→func branchExistsCLI(branchName string) error {
1199→	ctx := context.Background()
1200→	cmd := exec.CommandContext(ctx, "git", "show-ref", "--verify", "--quiet", "refs/heads/"+branchName) //nolint:gosec // branchName comes from internal shadow branch naming
1201→	if err := cmd.Run(); err != nil {
1202→		return fmt.Errorf("branch %s not found: %w", branchName, err)
