1207→// HardResetWithProtection performs a git reset --hard to the specified commit.
1208→// Uses the git CLI instead of go-git because go-git's HardReset incorrectly
1209→// deletes untracked directories (like .entire/) even when they're in .gitignore.
1210→// Returns the short commit ID (7 chars) on success for display purposes.
1211→func HardResetWithProtection(commitHash plumbing.Hash) (shortID string, err error) {
1212→	ctx := context.Background()
1213→	hashStr := commitHash.String()
1214→	cmd := exec.CommandContext(ctx, "git", "reset", "--hard", hashStr) //nolint:gosec // hashStr is a plumbing.Hash, not user input
1215→	if output, err := cmd.CombinedOutput(); err != nil {
1216→		return "", fmt.Errorf("reset failed: %s: %w", strings.TrimSpace(string(output)), err)
1217→	}
1218→
1219→	// Return short commit ID for display
1220→	shortID = hashStr
1221→	if len(shortID) > 7 {
1222→		shortID = shortID[:7]
1223→	}
1224→	return shortID, nil
1225→}
