1227→// collectUntrackedFiles collects all untracked files in the working directory.
1228→// This is used to capture the initial state when starting a session,
1229→// ensuring untracked files present at session start are preserved during rewind.
1230→// Excludes protected directories (.git/, .entire/, and agent config directories).
1231→// Works correctly from any subdirectory within the repository.
1232→func collectUntrackedFiles() ([]string, error) {
1233→	// Get repository root to walk from there
1234→	repoRoot, err := GetWorktreePath()
1235→	if err != nil {
1236→		repoRoot = "." // Fallback to current directory
1237→	}
1238→
1239→	var untrackedFiles []string
1240→	err = filepath.Walk(repoRoot, func(path string, info os.FileInfo, walkErr error) error {
1241→		if walkErr != nil {
1242→			return nil //nolint:nilerr // Skip filesystem errors during walk
1243→		}
1244→
1245→		// Get path relative to repo root
1246→		relPath, err := filepath.Rel(repoRoot, path)
1247→		if err != nil {
1248→			return nil //nolint:nilerr // Skip paths we can't make relative
1249→		}
1250→
1251→		// Skip directories
1252→		if info.IsDir() {
1253→			if isProtectedPath(relPath) {
1254→				return filepath.SkipDir
1255→			}
1256→			return nil
1257→		}
1258→
1259→		// Skip files in protected directories (shouldn't reach here due to SkipDir, but safety check)
1260→		if isProtectedPath(relPath) {
1261→			return nil
1262→		}
1263→
1264→		untrackedFiles = append(untrackedFiles, relPath)
1265→		return nil
1266→	})
1267→	if err != nil {
1268→		return nil, fmt.Errorf("failed to walk directory: %w", err)
1269→	}
1270→
1271→	return untrackedFiles, nil
1272→}
