1274→// ExtractSessionIDFromCommit extracts the session ID from a commit's trailers.
1275→// It checks the Entire-Session trailer first, then falls back to extracting from
1276→// the metadata directory path in the Entire-Metadata trailer.
1277→// Returns empty string if no session ID is found.
1278→func ExtractSessionIDFromCommit(commit *object.Commit) string {
1279→	// Try Entire-Session trailer first
1280→	if sessionID, found := trailers.ParseSession(commit.Message); found {
1281→		return sessionID
1282→	}
1283→
1284→	// Try extracting from metadata directory (last path component)
1285→	if metadataDir, found := trailers.ParseMetadata(commit.Message); found {
1286→		return filepath.Base(metadataDir)
1287→	}
1288→
1289→	return ""
1290→}
