1301→// createCommit creates a commit object
1302→func createCommit(repo *git.Repository, treeHash, parentHash plumbing.Hash, message, authorName, authorEmail string) (plumbing.Hash, error) { //nolint:unparam // already present in codebase
1303→	now := time.Now()
1304→	sig := object.Signature{
1305→		Name:  authorName,
1306→		Email: authorEmail,
1307→		When:  now,
1308→	}
1309→
1310→	commit := &object.Commit{
1311→		TreeHash:  treeHash,
1312→		Author:    sig,
1313→		Committer: sig,
1314→		Message:   message,
1315→	}
1316→
1317→	// Add parent if not a new branch
1318→	if parentHash != plumbing.ZeroHash {
1319→		commit.ParentHashes = []plumbing.Hash{parentHash}
1320→	}
1321→
1322→	obj := repo.Storer.NewEncodedObject()
1323→	if err := commit.Encode(obj); err != nil {
1324→		return plumbing.ZeroHash, fmt.Errorf("failed to encode commit: %w", err)
1325→	}
1326→
1327→	hash, err := repo.Storer.SetEncodedObject(obj)
1328→	if err != nil {
1329→		return plumbing.ZeroHash, fmt.Errorf("failed to store commit: %w", err)
1330→	}
1331→
1332→	return hash, nil
1333→}
