1335→// getSessionDescriptionFromTree reads the first line of prompt.txt or context.md from a git tree.
1336→// This is the tree-based equivalent of getSessionDescription (which reads from filesystem).
1337→//
1338→// If metadataDir is provided, looks for files at metadataDir/prompt.txt or metadataDir/context.md.
1339→// If metadataDir is empty, first tries the root of the tree (for when the tree is already
1340→// the session directory, e.g., auto-commit strategy's sharded metadata), then falls back to
1341→// searching for .entire/metadata/*/prompt.txt or context.md (for full worktree trees).
1342→func getSessionDescriptionFromTree(tree *object.Tree, metadataDir string) string {
1343→	// Helper to read first line from a file in tree
1344→	readFirstLine := func(path string) string {
1345→		file, err := tree.File(path)
1346→		if err != nil {
1347→			return ""
1348→		}
1349→		content, err := file.Contents()
1350→		if err != nil {
1351→			return ""
1352→		}
1353→		lines := strings.SplitN(content, "\n", 2)
1354→		if len(lines) > 0 && lines[0] != "" {
1355→			desc := strings.TrimSpace(lines[0])
1356→			// Remove markdown header prefix if present
1357→			return strings.TrimPrefix(desc, "# ")
1358→		}
1359→		return ""
1360→	}
1361→
1362→	// If metadataDir is provided, look there directly
1363→	if metadataDir != "" {
1364→		if desc := readFirstLine(metadataDir + "/" + paths.PromptFileName); desc != "" {
1365→			return desc
1366→		}
1367→		if desc := readFirstLine(metadataDir + "/" + paths.ContextFileName); desc != "" {
1368→			return desc
1369→		}
1370→		return NoDescription
1371→	}
1372→
1373→	// No metadataDir provided - first try looking at the root of the tree
1374→	// (used when the tree is already the session directory)
1375→	if desc := readFirstLine(paths.PromptFileName); desc != "" {
1376→		return desc
1377→	}
1378→	if desc := readFirstLine(paths.ContextFileName); desc != "" {
1379→		return desc
1380→	}
1381→
1382→	// Fall back to searching for .entire/metadata/*/prompt.txt or context.md
1383→	// (used when the tree is the full worktree)
1384→	var desc string
1385→	//nolint:errcheck // We ignore errors here as we're just searching for a description
1386→	_ = tree.Files().ForEach(func(f *object.File) error {
1387→		if desc != "" {
1388→			return nil // Already found description
1389→		}
1390→		name := f.Name
1391→		if strings.Contains(name, ".entire/metadata/") {
1392→			if strings.HasSuffix(name, "/"+paths.PromptFileName) || strings.HasSuffix(name, "/"+paths.ContextFileName) {
1393→				content, err := f.Contents()
1394→				if err != nil {
1395→					return nil //nolint:nilerr // Skip files we can't read, continue searching
1396→				}
1397→				lines := strings.SplitN(content, "\n", 2)
1398→				if len(lines) > 0 && lines[0] != "" {
1399→					desc = strings.TrimSpace(lines[0])
1400→					desc = strings.TrimPrefix(desc, "# ")
1401→				}
1402→			}
1403→		}
1404→		return nil
1405→	})
1406→
1407→	if desc != "" {
1408→		return desc
1409→	}
1410→	return NoDescription
1411→}
