1413→// GetGitAuthorFromRepo retrieves the git user.name and user.email from the repository config.
1414→// It checks local config first, then falls back to global config.
1415→// Returns ("Unknown", "unknown@local") if no user is configured - this allows
1416→// operations to proceed even without git user config, which is especially useful
1417→// for internal metadata commits on branches like entire/checkpoints/v1.
1418→func GetGitAuthorFromRepo(repo *git.Repository) (name, email string) {
1419→	// Get repository config (includes local settings)
1420→	cfg, err := repo.Config()
1421→	if err == nil {
1422→		name = cfg.User.Name
1423→		email = cfg.User.Email
1424→	}
1425→
1426→	// If not found in local config, try global config
1427→	if name == "" || email == "" {
1428→		globalCfg, err := config.LoadConfig(config.GlobalScope)
1429→		if err == nil {
1430→			if name == "" {
1431→				name = globalCfg.User.Name
1432→			}
1433→			if email == "" {
1434→				email = globalCfg.User.Email
1435→			}
1436→		}
1437→	}
1438→
1439→	// Provide sensible defaults if git user is not configured
1440→	if name == "" {
1441→		name = "Unknown"
1442→	}
1443→	if email == "" {
1444→		email = "unknown@local"
1445→	}
1446→
1447→	return name, email
1448→}
