1450→// GetCurrentBranchName returns the short name of the current branch if HEAD points to a branch.
1451→// Returns an empty string if in detached HEAD state or if there's an error reading HEAD.
1452→// This is used to capture branch metadata for checkpoints.
1453→func GetCurrentBranchName(repo *git.Repository) string {
1454→	head, err := repo.Head()
1455→	if err != nil || !head.Name().IsBranch() {
1456→		return ""
1457→	}
1458→	return head.Name().Short()
1459→}
