1461→// getMainBranchHash returns the hash of the main branch (main or master).
1462→// Returns ZeroHash if no main branch is found.
1463→func GetMainBranchHash(repo *git.Repository) plumbing.Hash {
1464→	// Try common main branch names
1465→	for _, branchName := range []string{branchMain, branchMaster} {
1466→		// Try local branch first
1467→		ref, err := repo.Reference(plumbing.NewBranchReferenceName(branchName), true)
1468→		if err == nil {
1469→			return ref.Hash()
1470→		}
1471→		// Try remote tracking branch
1472→		ref, err = repo.Reference(plumbing.NewRemoteReferenceName("origin", branchName), true)
1473→		if err == nil {
1474→			return ref.Hash()
1475→		}
1476→	}
1477→	return plumbing.ZeroHash
1478→}
