1480→// GetDefaultBranchName returns the name of the default branch.
1481→// First checks origin/HEAD, then falls back to checking if main/master exists.
1482→// Returns empty string if unable to determine.
1483→// NOTE: Duplicated from cli/git_operations.go - see ENT-129 for consolidation.
1484→func GetDefaultBranchName(repo *git.Repository) string {
1485→	// Try to get the symbolic reference for origin/HEAD
1486→	// Use resolved=false to get the symbolic ref itself, then extract its target
1487→	ref, err := repo.Reference(plumbing.NewRemoteReferenceName("origin", "HEAD"), false)
1488→	if err == nil && ref != nil && ref.Type() == plumbing.SymbolicReference {
1489→		target := ref.Target().String()
1490→		if branchName, found := strings.CutPrefix(target, "refs/remotes/origin/"); found {
1491→			return branchName
1492→		}
1493→	}
1494→
1495→	// Fallback: check if origin/main or origin/master exists
1496→	if _, err := repo.Reference(plumbing.NewRemoteReferenceName("origin", branchMain), true); err == nil {
1497→		return branchMain
1498→	}
1499→	if _, err := repo.Reference(plumbing.NewRemoteReferenceName("origin", branchMaster), true); err == nil {
1500→		return branchMaster
1501→	}
1502→
1503→	// Final fallback: check local branches
1504→	if _, err := repo.Reference(plumbing.NewBranchReferenceName(branchMain), true); err == nil {
1505→		return branchMain
1506→	}
1507→	if _, err := repo.Reference(plumbing.NewBranchReferenceName(branchMaster), true); err == nil {
1508→		return branchMaster
1509→	}
1510→
1511→	return ""
1512→}
1513→
1514→// IsOnDefaultBranch checks if the repository HEAD is on the default branch.
1515→// Returns (isOnDefault, currentBranchName).
1516→// NOTE: Duplicated from cli/git_operations.go - see ENT-129 for consolidation.
1517→func IsOnDefaultBranch(repo *git.Repository) (bool, string) {
1518→	currentBranch := GetCurrentBranchName(repo)
1519→	if currentBranch == "" {
1520→		return false, ""
1521→	}
1522→
1523→	defaultBranch := GetDefaultBranchName(repo)
1524→	if defaultBranch == "" {
1525→		// Can't determine default, check common names
1526→		if currentBranch == branchMain || currentBranch == branchMaster {
1527→			return true, currentBranch
1528→		}
1529→		return false, currentBranch
1530→	}
1531→
1532→	return currentBranch == defaultBranch, currentBranch
1533→}
