 17→// Shadow strategy session state methods.
 18→// Uses session.StateStore for persistence.
 19→
 20→// loadSessionState loads session state using the StateStore.
 21→func (s *ManualCommitStrategy) loadSessionState(sessionID string) (*SessionState, error) {
 22→	store, err := s.getStateStore()
 23→	if err != nil {
 24→		return nil, err
 25→	}
 26→	state, err := store.Load(context.Background(), sessionID)
 27→	if err != nil {
 28→		return nil, fmt.Errorf("failed to load session state: %w", err)
 29→	}
 30→	return state, nil
 31→}
 32→
 33→// saveSessionState saves session state using the StateStore.
 34→func (s *ManualCommitStrategy) saveSessionState(state *SessionState) error {
 35→	store, err := s.getStateStore()
 36→	if err != nil {
 37→		return err
 38→	}
 39→	if err := store.Save(context.Background(), state); err != nil {
 40→		return fmt.Errorf("failed to save session state: %w", err)
 41→	}
 42→	return nil
 43→}
 44→
 45→// clearSessionState clears session state using the StateStore.
 46→func (s *ManualCommitStrategy) clearSessionState(sessionID string) error {
 47→	store, err := s.getStateStore()
 48→	if err != nil {
 49→		return err
 50→	}
 51→	if err := store.Clear(context.Background(), sessionID); err != nil {
 52→		return fmt.Errorf("failed to clear session state: %w", err)
 53→	}
 54→	return nil
 55→}
 56→
 57→// listAllSessionStates returns all active session states.
 58→// It filters out orphaned sessions whose shadow branch no longer exists.
 59→func (s *ManualCommitStrategy) listAllSessionStates() ([]*SessionState, error) {
 60→	store, err := s.getStateStore()
 61→	if err != nil {
 62→		return nil, fmt.Errorf("failed to get state store: %w", err)
 63→	}
 64→
 65→	sessionStates, err := store.List(context.Background())
 66→	if err != nil {
 67→		return nil, fmt.Errorf("failed to list session states: %w", err)
 68→	}
 69→
 70→	if len(sessionStates) == 0 {
 71→		return nil, nil
 72→	}
 73→
 74→	repo, err := OpenRepository()
 75→	if err != nil {
 76→		return nil, fmt.Errorf("failed to open git repository: %w", err)
 77→	}
 78→
 79→	var states []*SessionState
 80→	for _, sessionState := range sessionStates {
 81→		state := sessionState
 82→
 83→		// Skip and cleanup orphaned sessions whose shadow branch no longer exists.
 84→		// Keep active sessions (shadow branch may not be created yet) and sessions
 85→		// with LastCheckpointID (needed for checkpoint ID reuse on subsequent commits).
 86→		// Clean up everything else: stale pre-state-machine sessions (empty phase),
 87→		// IDLE/ENDED sessions that were never condensed, etc.
 88→		shadowBranch := getShadowBranchNameForCommit(state.BaseCommit, state.WorktreeID)
 89→		refName := plumbing.NewBranchReferenceName(shadowBranch)
 90→		if _, err := repo.Reference(refName, true); err != nil {
 91→			if !state.Phase.IsActive() && state.LastCheckpointID.IsEmpty() {
 92→				//nolint:errcheck,gosec // G104: Cleanup is best-effort, shouldn't fail the list operation
 93→				store.Clear(context.Background(), state.SessionID)
 94→				continue
 95→			}
 96→		}
 97→
 98→		states = append(states, state)
 99→	}
100→	return states, nil
101→}
