 168→// isFullyEnabled checks whether Entire is already fully set up.
 169→// Returns whether it's fully enabled, and if so, the agent type display name and config file path.
 170→func isFullyEnabled() (enabled bool, agentDesc string, configPath string) {
 171→	// Check settings exist and Enabled == true
 172→	s, err := LoadEntireSettings()
 173→	if err != nil || !s.Enabled {
 174→		return false, "", ""
 175→	}
 176→
 177→	// Check any agent hooks installed (not just Claude Code — works with Gemini too)
 178→	installedAgents := GetAgentsWithHooksInstalled()
 179→	if len(installedAgents) == 0 {
 180→		return false, "", ""
 181→	}
 182→
 183→	// Check git hooks installed
 184→	if !strategy.IsGitHookInstalled() {
 185→		return false, "", ""
 186→	}
 187→
 188→	// Check .entire directory exists
 189→	if !checkEntireDirExists() {
 190→		return false, "", ""
 191→	}
 192→
 193→	// Determine agent description from first installed agent
 194→	desc := string(installedAgents[0]) // fallback to agent name
 195→	if ag, err := agent.Get(installedAgents[0]); err == nil {
 196→		desc = string(ag.Type())
 197→	}
 198→
 199→	// Determine config path - check if local settings exists, otherwise show project settings
 200→	entireDirAbs, err := paths.AbsPath(paths.EntireDir)
 201→	if err != nil {
 202→		entireDirAbs = paths.EntireDir
 203→	}
 204→	configDisplay := configDisplayProject
 205→	localSettingsPath := filepath.Join(entireDirAbs, "settings.local.json")
 206→	if _, err := os.Stat(localSettingsPath); err == nil {
 207→		configDisplay = configDisplayLocal
 208→	}
 209→
 210→	return true, desc, configDisplay
 211→}
