 213→// runEnableWithStrategy enables Entire with a specified strategy (non-interactive).
 214→// The selectedStrategy can be either a display name (manual-commit, auto-commit)
 215→// or an internal name (manual-commit, auto-commit).
 216→func runEnableWithStrategy(w io.Writer, selectedStrategy string, localDev, _, useLocalSettings, useProjectSettings, forceHooks, skipPushSessions, telemetry bool) error {
 217→	// Map the strategy to internal name if it's a display name
 218→	internalStrategy := selectedStrategy
 219→	if mapped, ok := strategyDisplayToInternal[selectedStrategy]; ok {
 220→		internalStrategy = mapped
 221→	}
 222→
 223→	// Validate the strategy exists
 224→	strat, err := strategy.Get(internalStrategy)
 225→	if err != nil {
 226→		return fmt.Errorf("unknown strategy: %s (use manual-commit or auto-commit)", selectedStrategy)
 227→	}
 228→
 229→	// Detect default agent
 230→	ag := agent.Default()
 231→	agentType := string(agent.AgentTypeClaudeCode)
 232→	if ag != nil {
 233→		agentType = string(ag.Type())
 234→	}
 235→	fmt.Fprintf(w, "Agent: %s (use --agent to change)\n\n", agentType)
 236→
 237→	// Setup Claude Code hooks (agent hooks don't depend on settings)
 238→	if _, err := setupClaudeCodeHook(localDev, forceHooks); err != nil {
 239→		return fmt.Errorf("failed to setup Claude Code hooks: %w", err)
 240→	}
 241→
 242→	// Setup .entire directory
 243→	if _, err := setupEntireDirectory(); err != nil {
 244→		return fmt.Errorf("failed to setup .entire directory: %w", err)
 245→	}
 246→
 247→	// Load existing settings to preserve other options (like strategy_options.push)
 248→	settings, err := LoadEntireSettings()
 249→	if err != nil {
 250→		// If we can't load, start with defaults
 251→		settings = &EntireSettings{}
 252→	}
 253→	// Update the specific fields
 254→	settings.Strategy = internalStrategy
 255→	settings.LocalDev = localDev
 256→	settings.Enabled = true
 257→
 258→	// Set push_sessions option if --skip-push-sessions flag was provided
 259→	if skipPushSessions {
 260→		if settings.StrategyOptions == nil {
 261→			settings.StrategyOptions = make(map[string]interface{})
 262→		}
 263→		settings.StrategyOptions["push_sessions"] = false
 264→	}
 265→
 266→	// Handle telemetry for non-interactive mode
 267→	// Note: if telemetry is nil (not configured), it defaults to disabled
 268→	if !telemetry || os.Getenv("ENTIRE_TELEMETRY_OPTOUT") != "" {
 269→		f := false
 270→		settings.Telemetry = &f
 271→	}
 272→
 273→	// Determine which settings file to write to
 274→	entireDirAbs, err := paths.AbsPath(paths.EntireDir)
 275→	if err != nil {
 276→		entireDirAbs = paths.EntireDir // Fallback to relative
 277→	}
 278→	shouldUseLocal, showNotification := determineSettingsTarget(entireDirAbs, useLocalSettings, useProjectSettings)
 279→
 280→	if showNotification {
 281→		fmt.Fprintln(w, "Info: Project settings exist. Saving to settings.local.json instead.")
 282→		fmt.Fprintln(w, "  Use --project to update the project settings file.")
 283→	}
 284→
 285→	configDisplay := configDisplayProject
 286→	if shouldUseLocal {
 287→		if err := SaveEntireSettingsLocal(settings); err != nil {
 288→			return fmt.Errorf("failed to save local settings: %w", err)
 289→		}
 290→		configDisplay = configDisplayLocal
 291→	} else {
 292→		if err := SaveEntireSettings(settings); err != nil {
 293→			return fmt.Errorf("failed to save settings: %w", err)
 294→		}
 295→	}
 296→
 297→	// Install git hooks AFTER saving settings (InstallGitHook reads local_dev from settings)
 298→	if _, err := strategy.InstallGitHook(true); err != nil {
 299→		return fmt.Errorf("failed to install git hooks: %w", err)
 300→	}
 301→	fmt.Fprintln(w, "✓ Hooks installed")
 302→	fmt.Fprintf(w, "✓ Project configured (%s)\n", configDisplay)
 303→
 304→	// Let the strategy handle its own setup requirements
 305→	if err := strat.EnsureSetup(); err != nil {
 306→		return fmt.Errorf("failed to setup strategy: %w", err)
 307→	}
 308→
 309→	fmt.Fprintln(w, "\nReady.")
 310→
 311→	return nil
 312→}
