 314→// runEnableInteractive runs the interactive enable flow.
 315→func runEnableInteractive(w io.Writer, localDev, _, useLocalSettings, useProjectSettings, forceHooks, skipPushSessions, telemetry bool) error {
 316→	// Check if already fully enabled — show summary and return early.
 317→	// Skip early return if any configuration flags are set (user wants to reconfigure).
 318→	hasConfigFlags := forceHooks || skipPushSessions || !telemetry || useLocalSettings || useProjectSettings || localDev
 319→	if !hasConfigFlags {
 320→		if fullyEnabled, agentDesc, configPath := isFullyEnabled(); fullyEnabled {
 321→			fmt.Fprintln(w, "Already enabled. Everything looks good.")
 322→			fmt.Fprintln(w)
 323→			fmt.Fprintf(w, "  Agent: %s\n", agentDesc)
 324→			fmt.Fprintf(w, "  Config: %s\n", configPath)
 325→			return nil
 326→		}
 327→	}
 328→
 329→	// Detect default agent
 330→	ag := agent.Default()
 331→	agentType := string(agent.AgentTypeClaudeCode)
 332→	if ag != nil {
 333→		agentType = string(ag.Type())
 334→	}
 335→	fmt.Fprintf(w, "Agent: %s (use --agent to change)\n\n", agentType)
 336→
 337→	// Setup Claude Code hooks (agent hooks don't depend on settings)
 338→	if _, err := setupClaudeCodeHook(localDev, forceHooks); err != nil {
 339→		return fmt.Errorf("failed to setup Claude Code hooks: %w", err)
 340→	}
 341→
 342→	// Setup .entire directory
 343→	if _, err := setupEntireDirectory(); err != nil {
 344→		return fmt.Errorf("failed to setup .entire directory: %w", err)
 345→	}
 346→
 347→	// Use the default strategy (manual-commit)
 348→	internalStrategy := strategy.DefaultStrategyName
 349→
 350→	// Load existing settings to preserve other options (like strategy_options.push)
 351→	settings, err := LoadEntireSettings()
 352→	if err != nil {
 353→		// If we can't load, start with defaults
 354→		settings = &EntireSettings{}
 355→	}
 356→	// Update the specific fields
 357→	settings.Strategy = internalStrategy
 358→	settings.LocalDev = localDev
 359→	settings.Enabled = true
 360→
 361→	// Set push_sessions option if --skip-push-sessions flag was provided
 362→	if skipPushSessions {
 363→		if settings.StrategyOptions == nil {
 364→			settings.StrategyOptions = make(map[string]interface{})
 365→		}
 366→		settings.StrategyOptions["push_sessions"] = false
 367→	}
 368→
 369→	// Determine which settings file to write to
 370→	// First run always creates settings.json (no prompt)
 371→	entireDirAbs, err := paths.AbsPath(paths.EntireDir)
 372→	if err != nil {
 373→		entireDirAbs = paths.EntireDir // Fallback to relative
 374→	}
 375→	shouldUseLocal, showNotification := determineSettingsTarget(entireDirAbs, useLocalSettings, useProjectSettings)
 376→
 377→	if showNotification {
 378→		fmt.Fprintln(w, "Info: Project settings exist. Saving to settings.local.json instead.")
 379→		fmt.Fprintln(w, "  Use --project to update the project settings file.")
 380→	}
 381→
 382→	// Helper to save settings to the appropriate file
 383→	saveSettings := func() error {
 384→		if shouldUseLocal {
 385→			return SaveEntireSettingsLocal(settings)
 386→		}
 387→		return SaveEntireSettings(settings)
 388→	}
 389→
 390→	// Save settings before telemetry prompt so config is persisted even if the user cancels
 391→	if err := saveSettings(); err != nil {
 392→		return fmt.Errorf("failed to save settings: %w", err)
 393→	}
 394→
 395→	// Install git hooks AFTER saving settings (InstallGitHook reads local_dev from settings)
 396→	if _, err := strategy.InstallGitHook(true); err != nil {
 397→		return fmt.Errorf("failed to install git hooks: %w", err)
 398→	}
 399→	fmt.Fprintln(w, "✓ Hooks installed")
 400→
 401→	configDisplay := configDisplayProject
 402→	if shouldUseLocal {
 403→		configDisplay = configDisplayLocal
 404→	}
 405→	fmt.Fprintf(w, "✓ Project configured (%s)\n", configDisplay)
 406→
 407→	// Ask about telemetry consent (only if not already asked)
 408→	fmt.Fprintln(w)
 409→	if err := promptTelemetryConsent(settings, telemetry); err != nil {
 410→		return fmt.Errorf("telemetry consent: %w", err)
 411→	}
 412→	// Save again to persist telemetry choice
 413→	if err := saveSettings(); err != nil {
 414→		return fmt.Errorf("failed to save settings: %w", err)
 415→	}
 416→
 417→	// Let the strategy handle its own setup requirements
 418→	strat, err := strategy.Get(internalStrategy)
 419→	if err != nil {
 420→		return fmt.Errorf("failed to get strategy: %w", err)
 421→	}
 422→	if err := strat.EnsureSetup(); err != nil {
 423→		return fmt.Errorf("failed to setup strategy: %w", err)
 424→	}
 425→
 426→	fmt.Fprintln(w, "\nReady.")
 427→
 428→	return nil
 429→}
