 559→	}
 560→
 561→	// Load existing settings to preserve other options (like strategy_options.push)
 562→	settings, err := LoadEntireSettings()
 563→	if err != nil {
 564→		// If we can't load, start with defaults
 565→		settings = &EntireSettings{Strategy: strategy.DefaultStrategyName}
 566→	}
 567→	settings.Enabled = true
 568→	if localDev {
 569→		settings.LocalDev = localDev
 570→	}
 571→
 572→	// Set push_sessions option if --skip-push-sessions flag was provided
 573→	if skipPushSessions {
 574→		if settings.StrategyOptions == nil {
 575→			settings.StrategyOptions = make(map[string]interface{})
 576→		}
 577→		settings.StrategyOptions["push_sessions"] = false
 578→	}
 579→
 580→	// Set strategy if provided
 581→	if strategyName != "" {
 582→		// Map display name to internal name if needed
 583→		internalStrategy := strategyName
 584→		if mapped, ok := strategyDisplayToInternal[strategyName]; ok {
 585→			internalStrategy = mapped
 586→		}
 587→		// Validate the strategy exists
 588→		if _, err := strategy.Get(internalStrategy); err != nil {
 589→			return fmt.Errorf("unknown strategy: %s (use manual-commit or auto-commit)", strategyName)
 590→		}
 591→		settings.Strategy = internalStrategy
 592→	}
 593→
 594→	// Handle telemetry for non-interactive mode
 595→	// Note: if telemetry is nil (not configured), it defaults to disabled
 596→	if !telemetry || os.Getenv("ENTIRE_TELEMETRY_OPTOUT") != "" {
 597→		f := false
 598→		settings.Telemetry = &f
 599→	}
 600→
 601→	if err := SaveEntireSettings(settings); err != nil {
 602→		return fmt.Errorf("failed to save settings: %w", err)
 603→	}
 604→
 605→	// Install git hooks AFTER saving settings (InstallGitHook reads local_dev from settings)
 606→	if _, err := strategy.InstallGitHook(true); err != nil {
 607→		return fmt.Errorf("failed to install git hooks: %w", err)
 608→	}
 609→
 610→	if installedHooks == 0 {
 611→		msg := fmt.Sprintf("Hooks for %s already installed", ag.Description())
 612→		if agentName == agent.AgentNameGemini {
 613→			msg += " (Preview)"
 614→		}
 615→		fmt.Fprintf(w, "%s\n", msg)
 616→	} else {
 617→		msg := fmt.Sprintf("Installed %d hooks for %s", installedHooks, ag.Description())
 618→		if agentName == agent.AgentNameGemini {
 619→			msg += " (Preview)"
 620→		}
 621→		fmt.Fprintf(w, "%s\n", msg)
 622→	}
 623→
 624→	fmt.Fprintf(w, "✓ Project configured (%s)\n", configDisplayProject)
 625→
 626→	// Let the strategy handle its own setup requirements (creates entire/checkpoints/v1 branch, etc.)
 627→	strat, err := strategy.Get(settings.Strategy)
 628→	if err != nil {
 629→		return fmt.Errorf("failed to get strategy: %w", err)
 630→	}
 631→	if err := strat.EnsureSetup(); err != nil {
 632→		return fmt.Errorf("failed to setup strategy: %w", err)
 633→	}
 634→
 635→	fmt.Fprintln(w, "\nReady.")
 636→
 637→	return nil
 638→}
