 648→// determineSettingsTarget decides whether to write to settings.local.json based on:
 649→// - Whether settings.json already exists
 650→// - The --local and --project flags
 651→// Returns (useLocal, showNotification).
 652→func determineSettingsTarget(entireDir string, useLocal, useProject bool) (bool, bool) {
 653→	// Explicit --local flag always uses local settings
 654→	if useLocal {
 655→		return true, false
 656→	}
 657→
 658→	// Explicit --project flag always uses project settings
 659→	if useProject {
 660→		return false, false
 661→	}
 662→
 663→	// No flags specified - check if settings file exists
 664→	settingsPath := filepath.Join(entireDir, paths.SettingsFileName)
 665→	if _, err := os.Stat(settingsPath); err == nil {
 666→		// Settings file exists - auto-redirect to local with notification
 667→		return true, true
 668→	}
 669→
 670→	// Settings file doesn't exist - create it
 671→	return false, false
 672→}
