 743→// shellCompletionComment is the comment preceding the completion line
 744→const shellCompletionComment = "# Entire CLI shell completion"
 745→
 746→// errUnsupportedShell is returned when the user's shell is not supported for completion.
 747→var errUnsupportedShell = errors.New("unsupported shell")
 748→
 749→// shellCompletionTarget returns the rc file path and completion lines for the
 750→// user's current shell.
 751→func shellCompletionTarget() (shellName, rcFile, completionLine string, err error) {
 752→	home, err := os.UserHomeDir()
 753→	if err != nil {
 754→		return "", "", "", fmt.Errorf("cannot determine home directory: %w", err)
 755→	}
 756→
 757→	shell := os.Getenv("SHELL")
 758→	switch {
 759→	case strings.Contains(shell, "zsh"):
 760→		return "Zsh",
 761→			filepath.Join(home, ".zshrc"),
 762→			"autoload -Uz compinit && compinit && source <(entire completion zsh)",
 763→			nil
 764→	case strings.Contains(shell, "bash"):
 765→		bashRC := filepath.Join(home, ".bashrc")
 766→		if _, err := os.Stat(filepath.Join(home, ".bash_profile")); err == nil {
 767→			bashRC = filepath.Join(home, ".bash_profile")
 768→		}
 769→		return "Bash",
 770→			bashRC,
 771→			"source <(entire completion bash)",
 772→			nil
 773→	case strings.Contains(shell, "fish"):
 774→		return "Fish",
 775→			filepath.Join(home, ".config", "fish", "config.fish"),
 776→			"entire completion fish | source",
 777→			nil
 778→	default:
 779→		return "", "", "", errUnsupportedShell
 780→	}
 781→}
 782→
 783→// promptShellCompletion offers to add shell completion to the user's rc file.
 784→// Only prompts if completion is not already configured.
 785→func promptShellCompletion(w io.Writer) error {
 786→	shellName, rcFile, completionLine, err := shellCompletionTarget()
 787→	if err != nil {
 788→		if errors.Is(err, errUnsupportedShell) {
 789→			fmt.Fprintf(w, "Note: Shell completion not available for your shell. Supported: zsh, bash, fish.\n")
 790→			return nil
 791→		}
 792→		return fmt.Errorf("shell completion: %w", err)
 793→	}
 794→
 795→	if isCompletionConfigured(rcFile) {
 796→		fmt.Fprintf(w, "✓ Shell completion already configured in %s\n", rcFile)
 797→		return nil
 798→	}
 799→
 800→	var selected string
 801→	form := NewAccessibleForm(
 802→		huh.NewGroup(
 803→			huh.NewSelect[string]().
 804→				Title(fmt.Sprintf("Enable shell completion? (detected: %s)", shellName)).
 805→				Options(
 806→					huh.NewOption("Yes", "yes"),
 807→					huh.NewOption("No", "no"),
 808→				).
 809→				Value(&selected),
 810→		),
 811→	)
 812→
 813→	if err := form.Run(); err != nil {
 814→		//nolint:nilerr // User cancelled - not a fatal error, just skip
 815→		return nil
 816→	}
 817→
 818→	if selected != "yes" {
 819→		return nil
 820→	}
 821→
 822→	if err := appendShellCompletion(rcFile, completionLine); err != nil {
 823→		return fmt.Errorf("failed to update %s: %w", rcFile, err)
 824→	}
 825→
 826→	fmt.Fprintf(w, "✓ Shell completion added to %s\n", rcFile)
 827→	fmt.Fprintln(w, "  Restart your shell to activate")
 828→
 829→	return nil
 830→}
 831→
 832→// isCompletionConfigured checks if shell completion is already in the rc file.
 833→func isCompletionConfigured(rcFile string) bool {
 834→	//nolint:gosec // G304: rcFile is constructed from home dir + known filename, not user input
 835→	content, err := os.ReadFile(rcFile)
 836→	if err != nil {
 837→		return false // File doesn't exist or can't read, treat as not configured
 838→	}
 839→	return strings.Contains(string(content), "entire completion")
 840→}
 841→
 842→// appendShellCompletion adds the completion line to the rc file.
 843→func appendShellCompletion(rcFile, completionLine string) error {
 844→	if err := os.MkdirAll(filepath.Dir(rcFile), 0o700); err != nil {
 845→		return fmt.Errorf("creating directory: %w", err)
 846→	}
 847→	//nolint:gosec // G302: Shell rc files need 0644 for user readability
 848→	f, err := os.OpenFile(rcFile, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0o644)
 849→	if err != nil {
 850→		return fmt.Errorf("opening file: %w", err)
 851→	}
 852→	defer f.Close()
 853→
 854→	_, err = f.WriteString("\n" + shellCompletionComment + "\n" + completionLine + "\n")
 855→	if err != nil {
 856→		return fmt.Errorf("writing completion: %w", err)
 857→	}
 858→	return nil
 859→}
