 904→// runUninstall completely removes Entire from the repository.
 905→func runUninstall(w, errW io.Writer, force bool) error {
 906→	// Check if we're in a git repository
 907→	if _, err := paths.RepoRoot(); err != nil {
 908→		fmt.Fprintln(errW, "Not a git repository. Nothing to uninstall.")
 909→		return NewSilentError(errors.New("not a git repository"))
 910→	}
 911→
 912→	// Gather counts for display
 913→	sessionStateCount := countSessionStates()
 914→	shadowBranchCount := countShadowBranches()
 915→	gitHooksInstalled := strategy.IsGitHookInstalled()
 916→	claudeHooksInstalled := checkClaudeCodeHooksInstalled()
 917→	geminiHooksInstalled := checkGeminiCLIHooksInstalled()
 918→	entireDirExists := checkEntireDirExists()
 919→
 920→	// Check if there's anything to uninstall
 921→	if !entireDirExists && !gitHooksInstalled && sessionStateCount == 0 &&
 922→		shadowBranchCount == 0 && !claudeHooksInstalled && !geminiHooksInstalled {
 923→		fmt.Fprintln(w, "Entire is not installed in this repository.")
 924→		return nil
 925→	}
 926→
 927→	// Show confirmation prompt unless --force
 928→	if !force {
 929→		fmt.Fprintln(w, "\nThis will completely remove Entire from this repository:")
 930→		if entireDirExists {
 931→			fmt.Fprintln(w, "  - .entire/ directory")
 932→		}
 933→		if gitHooksInstalled {
 934→			fmt.Fprintln(w, "  - Git hooks (prepare-commit-msg, commit-msg, post-commit, pre-push)")
 935→		}
 936→		if sessionStateCount > 0 {
 937→			fmt.Fprintf(w, "  - Session state files (%d)\n", sessionStateCount)
 938→		}
 939→		if shadowBranchCount > 0 {
 940→			fmt.Fprintf(w, "  - Shadow branches (%d)\n", shadowBranchCount)
 941→		}
 942→		switch {
 943→		case claudeHooksInstalled && geminiHooksInstalled:
 944→			fmt.Fprintln(w, "  - Agent hooks (Claude Code, Gemini CLI)")
 945→		case claudeHooksInstalled:
 946→			fmt.Fprintln(w, "  - Agent hooks (Claude Code)")
 947→		case geminiHooksInstalled:
 948→			fmt.Fprintln(w, "  - Agent hooks (Gemini CLI)")
 949→		}
 950→		fmt.Fprintln(w)
 951→
 952→		var confirmed bool
 953→		form := NewAccessibleForm(
 954→			huh.NewGroup(
 955→				huh.NewConfirm().
 956→					Title("Are you sure you want to uninstall Entire?").
 957→					Affirmative("Yes, uninstall").
 958→					Negative("Cancel").
 959→					Value(&confirmed),
 960→			),
 961→		)
 962→
 963→		if err := form.Run(); err != nil {
 964→			return fmt.Errorf("confirmation cancelled: %w", err)
 965→		}
 966→
 967→		if !confirmed {
 968→			fmt.Fprintln(w, "Uninstall cancelled.")
 969→			return nil
 970→		}
 971→	}
 972→
 973→	fmt.Fprintln(w, "\nUninstalling Entire CLI...")
 974→
 975→	// 1. Remove agent hooks (lowest risk)
 976→	if err := removeAgentHooks(w); err != nil {
 977→		fmt.Fprintf(errW, "Warning: failed to remove agent hooks: %v\n", err)
 978→	}
 979→
 980→	// 2. Remove git hooks
 981→	removed, err := strategy.RemoveGitHook()
 982→	if err != nil {
 983→		fmt.Fprintf(errW, "Warning: failed to remove git hooks: %v\n", err)
 984→	} else if removed > 0 {
 985→		fmt.Fprintf(w, "  Removed git hooks (%d)\n", removed)
 986→	}
 987→
 988→	// 3. Remove session state files
 989→	statesRemoved, err := removeAllSessionStates()
 990→	if err != nil {
 991→		fmt.Fprintf(errW, "Warning: failed to remove session states: %v\n", err)
 992→	} else if statesRemoved > 0 {
 993→		fmt.Fprintf(w, "  Removed session states (%d)\n", statesRemoved)
 994→	}
 995→
 996→	// 4. Remove .entire/ directory
 997→	if err := removeEntireDirectory(); err != nil {
 998→		fmt.Fprintf(errW, "Warning: failed to remove .entire directory: %v\n", err)
 999→	} else if entireDirExists {
1000→		fmt.Fprintln(w, "  Removed .entire directory")
1001→	}
1002→
1003→	// 5. Remove shadow branches
1004→	branchesRemoved, err := removeAllShadowBranches()
1005→	if err != nil {
1006→		fmt.Fprintf(errW, "Warning: failed to remove shadow branches: %v\n", err)
1007→	} else if branchesRemoved > 0 {
1008→		fmt.Fprintf(w, "  Removed %d shadow branches\n", branchesRemoved)
1009→	}
1010→
1011→	fmt.Fprintln(w, "\nEntire CLI uninstalled successfully.")
1012→	return nil
1013→}
