288→// logFileChanges logs the modified, new, and deleted files to stderr.
289→func logFileChanges(modified, newFiles, deleted []string) {
290→	fmt.Fprintf(os.Stderr, "Files modified during session (%d):\n", len(modified))
291→	for _, file := range modified {
292→		fmt.Fprintf(os.Stderr, "  - %s\n", file)
293→	}
294→	if len(newFiles) > 0 {
295→		fmt.Fprintf(os.Stderr, "New files created (%d):\n", len(newFiles))
296→		for _, file := range newFiles {
297→			fmt.Fprintf(os.Stderr, "  - %s\n", file)
298→		}
299→	}
300→	if len(deleted) > 0 {
301→		fmt.Fprintf(os.Stderr, "Files deleted (%d):\n", len(deleted))
302→		for _, file := range deleted {
303→			fmt.Fprintf(os.Stderr, "  - %s\n", file)
304→		}
305→	}
306→}
