308→// createContextFileForGemini creates a context.md file for Gemini sessions.
309→func createContextFileForGemini(contextFile, commitMessage, sessionID string, prompts []string, summary string) error {
310→	var sb strings.Builder
311→
312→	sb.WriteString("# Session Context\n\n")
313→	sb.WriteString(fmt.Sprintf("Session ID: %s\n", sessionID))
314→	sb.WriteString(fmt.Sprintf("Commit Message: %s\n\n", commitMessage))
315→
316→	if len(prompts) > 0 {
317→		sb.WriteString("## Prompts\n\n")
318→		for i, p := range prompts {
319→			sb.WriteString(fmt.Sprintf("### Prompt %d\n\n%s\n\n", i+1, p))
320→		}
321→	}
322→
323→	if summary != "" {
324→		sb.WriteString("## Summary\n\n")
325→		sb.WriteString(summary)
326→		sb.WriteString("\n")
327→	}
328→
329→	if err := os.WriteFile(contextFile, []byte(sb.String()), 0o600); err != nil {
330→		return fmt.Errorf("failed to write context file: %w", err)
331→	}
332→	return nil
333→}
