391→// handleGeminiBeforeAgent handles the BeforeAgent hook for Gemini CLI.
392→// This is equivalent to Claude Code's UserPromptSubmit - it fires when the user submits a prompt.
393→// We capture the initial state here so we can track what files were modified during the session.
394→// It also checks for concurrent sessions and blocks if another session has uncommitted changes.
395→func handleGeminiBeforeAgent() error {
396→	// Always use the Gemini agent for Gemini hooks (don't use GetAgent() which may
397→	// return Claude based on auto-detection in environments like VSCode)
398→	ag, err := agent.Get("gemini")
399→	if err != nil {
400→		return fmt.Errorf("failed to get gemini agent: %w", err)
401→	}
402→
403→	// Parse hook input - BeforeAgent provides user prompt info similar to UserPromptSubmit
404→	input, err := ag.ParseHookInput(agent.HookUserPromptSubmit, os.Stdin)
405→	if err != nil {
406→		return fmt.Errorf("failed to parse hook input: %w", err)
407→	}
408→
409→	logCtx := logging.WithAgent(logging.WithComponent(context.Background(), "hooks"), ag.Name())
410→
411→	// Log with prompt if available (Gemini provides the user's prompt in BeforeAgent)
412→	logArgs := []any{
413→		slog.String("hook", "before-agent"),
414→		slog.String("hook_type", "agent"),
415→		slog.String("model_session_id", input.SessionID),
416→		slog.String("transcript_path", input.SessionRef),
417→	}
418→	if input.UserPrompt != "" {
419→		// Truncate long prompts for logging
420→		promptPreview := input.UserPrompt
421→		if len(promptPreview) > 100 {
422→			promptPreview = promptPreview[:100] + "..."
423→		}
424→		logArgs = append(logArgs, slog.String("prompt_preview", promptPreview))
425→	}
426→	logging.Info(logCtx, "gemini-before-agent", logArgs...)
427→
428→	if input.SessionID == "" {
429→		return errors.New("no session_id in input")
430→	}
431→
432→	// Capture pre-prompt state with transcript position (Gemini-specific)
433→	// This captures both untracked files and the current transcript message count
434→	// so we can calculate token usage for just this prompt/response cycle
435→	if err := CaptureGeminiPrePromptState(input.SessionID, input.SessionRef); err != nil {
436→		return fmt.Errorf("failed to capture pre-prompt state: %w", err)
437→	}
438→
439→	// If strategy implements SessionInitializer, call it to initialize session state
440→	strat := GetStrategy()
441→	if initializer, ok := strat.(strategy.SessionInitializer); ok {
442→		agentType := ag.Type()
443→		if err := initializer.InitializeSession(input.SessionID, agentType, input.SessionRef, input.UserPrompt); err != nil {
444→			fmt.Fprintf(os.Stderr, "Warning: failed to initialize session state: %v\n", err)
445→		}
446→	}
447→
448→	return nil
449→}
