451→// handleGeminiAfterAgent handles the AfterAgent hook for Gemini CLI.
452→// This fires after the agent has finished processing and generated a response.
453→// This is equivalent to Claude Code's "Stop" hook - it commits the session changes with metadata.
454→// AfterAgent fires after EVERY user prompt/response cycle, making it the correct place
455→// for checkpoint creation (not SessionEnd, which only fires on explicit exit).
456→func handleGeminiAfterAgent() error {
457→	// Always use Gemini agent for Gemini hooks
458→	ag, err := agent.Get("gemini")
459→	if err != nil {
460→		return fmt.Errorf("failed to get gemini agent: %w", err)
461→	}
462→
463→	// Parse hook input using HookStop - AfterAgent provides the same data as Stop
464→	// (session_id, transcript_path) which is what we need for committing
465→	input, err := ag.ParseHookInput(agent.HookStop, os.Stdin)
466→	if err != nil {
467→		return fmt.Errorf("failed to parse hook input: %w", err)
468→	}
469→
470→	logCtx := logging.WithAgent(logging.WithComponent(context.Background(), "hooks"), ag.Name())
471→	logging.Info(logCtx, "gemini-after-agent",
472→		slog.String("hook", "after-agent"),
473→		slog.String("hook_type", "agent"),
474→		slog.String("model_session_id", input.SessionID),
475→		slog.String("transcript_path", input.SessionRef),
476→	)
477→
478→	sessionID := input.SessionID
479→	if sessionID == "" {
480→		sessionID = unknownSessionID
481→	}
482→
483→	transcriptPath := input.SessionRef
484→	if transcriptPath == "" || !fileExists(transcriptPath) {
485→		return fmt.Errorf("transcript file not found or empty: %s", transcriptPath)
486→	}
487→
488→	// Create session context and commit
489→	ctx := &geminiSessionContext{
490→		sessionID:      sessionID,
491→		transcriptPath: transcriptPath,
492→	}
493→
494→	if err := setupGeminiSessionDir(ctx); err != nil {
495→		return err
496→	}
497→
498→	if err := extractGeminiMetadata(ctx); err != nil {
499→		return err
500→	}
501→
502→	if err := commitGeminiSession(ctx); err != nil {
503→		return err
504→	}
505→
506→	// Transition session ACTIVE → IDLE (equivalent to Claude's transitionSessionTurnEnd)
507→	transitionSessionTurnEnd(sessionID)
508→
509→	return nil
510→}
